func homeHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/plain; charset=utf-8")
	fmt.Fprintln(w, "metrics server running")
}

func trackHandler(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "unknown"
	}
	requestID := r.URL.Query().Get("request_id")
	if requestID == "" {
		requestID = strconv.FormatInt(time.Now().UnixNano(), 10)
	}
	method := r.Method
	path := r.URL.Path
	status := "200"

	activeRequests.WithLabelValues(userID, requestID, method, path).Inc()
	defer activeRequests.WithLabelValues(userID, requestID, method, path).Dec()

	defer func() {
		duration := time.Since(start).Seconds()
		requestDurationSeconds.WithLabelValues(userID, requestID, method, path).Observe(duration)
		requestsTotal.WithLabelValues(userID, requestID, method, path, status).Inc()
	}()

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	_, _ = w.Write([]byte(`{"ok":true}`))
}

func eventHandler(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "unknown"
	}
	eventType := r.URL.Query().Get("event_type")
	if eventType == "" {
		eventType = "unknown"
	}

	userEvents.WithLabelValues(userID, eventType).Inc()

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	_, _ = w.Write([]byte(`{"recorded":true}`))
}

func stringsHasPrefix(s, prefix string) bool {
	return len(s) >= len(prefix) && s[:len(prefix)] == prefix
}